function settingsPanel(title, description, content) {
	return `<section class="coordina-card coordina-settings-panel"><div class="coordina-section-header"><div><h3>${escapeHtml(title)}</h3><p class="coordina-settings-panel__intro">${escapeHtml(description)}</p></div></div>${content}</section>`;
}

function settingsField(label, control, hint, className) {
	return `<div class="coordina-settings-field ${className || ''}"><label><span>${escapeHtml(label)}</span>${control}</label>${hint ? settingsHint(hint) : ''}</div>`;
}

function settingsBlock(title, description, body, extraClass) {
	return `<section class="coordina-settings-block ${extraClass || ''}"><div class="coordina-section-header"><div><h4>${escapeHtml(title)}</h4>${description ? `<p class="coordina-section-note">${escapeHtml(description)}</p>` : ''}</div></div>${body}</section>`;
}

function appearancePrimaryPalette() {
	return [
		{ key: 'cobalt', label: __('Cobalt blue', 'coordina'), color: '#2563eb' },
		{ key: 'spruce', label: __('Spruce green', 'coordina'), color: '#0f766e' },
		{ key: 'berry', label: __('Berry red', 'coordina'), color: '#be185d' },
		{ key: 'terracotta', label: __('Terracotta', 'coordina'), color: '#c2410c' },
		{ key: 'indigo', label: __('Indigo', 'coordina'), color: '#4f46e5' },
	];
}

function appearanceAccentPalette() {
	return [
		{ key: 'sky', label: __('Sky', 'coordina'), color: '#0ea5e9' },
		{ key: 'mint', label: __('Mint', 'coordina'), color: '#10b981' },
		{ key: 'amber', label: __('Amber', 'coordina'), color: '#f59e0b' },
		{ key: 'rose', label: __('Rose', 'coordina'), color: '#f43f5e' },
		{ key: 'lilac', label: __('Lilac', 'coordina'), color: '#a855f7' },
	];
}

function normalizeHex(value, fallback) {
	const color = String(value || '').trim();
	return /^#([0-9a-f]{3}|[0-9a-f]{6})$/i.test(color) ? color.toLowerCase() : fallback;
}

function paletteValue(options, key, fallback) {
	const found = (options || []).find((option) => String(option.key) === String(key));
	return found ? found.color : fallback;
}

function themePreview(primary, accent, label, compact) {
	return `<div class="coordina-theme-preview ${compact ? 'is-compact' : ''}"><span class="coordina-theme-preview__rail" style="background:${escapeHtml(primary)}"></span><div class="coordina-theme-preview__body"><strong>${escapeHtml(label || __('Theme preview', 'coordina'))}</strong><div class="coordina-theme-preview__swatches"><span class="coordina-theme-preview__swatch" style="background:${escapeHtml(primary)}"></span><span class="coordina-theme-preview__swatch" style="background:${escapeHtml(accent)}"></span></div></div></div>`;
}

